(function () {
  "use strict";

  const MobileCameraScan = {
    scanner: null,
    scannerId: "mobileCameraScannerRegion",
    modalId: "mobileCameraScannerModal",
    lastScanValue: "",
    lastScanAt: 0,
    isOpen: false,
    isStarting: false,
    isStopping: false,
    activeTargetInputId: "searchRefInput",
    activeSubmitMode: "button",
    activeSubmitButtonId: "btnSearchRef",
    activeSubmitCallback: null,
    preferredFormats: [
      Html5QrcodeSupportedFormats.CODE_128,
      Html5QrcodeSupportedFormats.CODE_39,
      Html5QrcodeSupportedFormats.EAN_13,
      Html5QrcodeSupportedFormats.EAN_8,
      Html5QrcodeSupportedFormats.CODABAR,
      Html5QrcodeSupportedFormats.UPC_A,
      Html5QrcodeSupportedFormats.UPC_E
    ],

    init() {
      if (!window.Html5Qrcode) {
        console.error("html5-qrcode wurde nicht geladen.");
        return;
      }

      this.injectStyles();
      this.injectModal();

      const openBtn = document.getElementById("btnOpenMobileScanner");
      if (openBtn) {
        openBtn.addEventListener("click", () => {
          this.openForSearch();
        });
      }

      const closeBtn = document.getElementById("mobileCameraScannerClose");
      if (closeBtn) {
        closeBtn.addEventListener("click", () => this.close());
      }

      const cancelBtn = document.getElementById("mobileCameraScannerCancel");
      if (cancelBtn) {
        cancelBtn.addEventListener("click", () => this.close());
      }

      const useBtn = document.getElementById("mobileCameraScannerUseValue");
      if (useBtn) {
        useBtn.addEventListener("click", () => this.applyManualValue());
      }

      const modal = document.getElementById(this.modalId);
      if (modal) {
        modal.addEventListener("click", (e) => {
          if (e.target === modal) this.close();
        });
      }

      const manualInput = document.getElementById("mobileCameraScannerManualInput");
      if (manualInput) {
        manualInput.addEventListener("keydown", (e) => {
          if (e.key === "Enter") {
            e.preventDefault();
            this.applyManualValue();
          }
        });
      }

      document.addEventListener("keydown", (e) => {
        if (e.key === "Escape" && this.isOpen) {
          this.close();
        }
      });

      document.addEventListener("visibilitychange", () => {
        if (document.hidden && this.isOpen) {
          this.stopScanner().catch(() => {});
        }
      });

      window.addEventListener("beforeunload", () => {
        if (this.isOpen) {
          this.stopScanner().catch(() => {});
        }
      });
    },

    openForSearch() {
      this.open({
        targetInputId: "searchRefInput",
        submitMode: "button",
        submitButtonId: "btnSearchRef"
      });
    },

    open(options = {}) {
      const {
        targetInputId = "searchRefInput",
        submitMode = "button",
        submitButtonId = "btnSearchRef",
        submitCallback = null,
        title = "Barcode mit Kamera scannen"
      } = options;

      this.activeTargetInputId = targetInputId;
      this.activeSubmitMode = submitMode;
      this.activeSubmitButtonId = submitButtonId;
      this.activeSubmitCallback = submitCallback;

      const titleEl = document.getElementById("mobileCameraScannerTitle");
      if (titleEl) titleEl.textContent = title;

      const modal = document.getElementById(this.modalId);
      if (!modal) return;

      this.resetUi();

      modal.classList.remove("d-none");
      modal.classList.add("d-flex");
      this.isOpen = true;

      this.startScanner().catch((err) => {
        console.error("Scannerstart fehlgeschlagen:", err);
        this.setStatus("Kamera konnte nicht gestartet werden. Du kannst den Code unten manuell eingeben.", "error");
      });
    },

    async close() {
      await this.stopScanner().catch(() => {});
      const modal = document.getElementById(this.modalId);
      if (modal) {
        modal.classList.add("d-none");
        modal.classList.remove("d-flex");
      }
      this.isOpen = false;
    },

    async startScanner() {
      if (this.isStarting) return;
      this.isStarting = true;

      try {
        const region = document.getElementById(this.scannerId);
        if (region) region.innerHTML = "";

        this.setStatus("Kamera wird gestartet …", "info");

        if (this.scanner) {
          await this.stopScanner().catch(() => {});
        }

        this.scanner = new Html5Qrcode(this.scannerId);

        await this.scanner.start(
          { facingMode: "environment" },
          {
            fps: 10,
            qrbox: { width: 260, height: 140 },
            rememberLastUsedCamera: true,
            formatsToSupport: this.preferredFormats,
            aspectRatio: 1.7777778
          },
          (decodedText) => this.onScanSuccess(decodedText),
          () => {}
        );

        this.setStatus("Kamera aktiv. Barcode ins Feld halten.", "success");
      } finally {
        this.isStarting = false;
      }
    },

    async stopScanner() {
      if (this.isStopping) return;
      this.isStopping = true;

      try {
        if (this.scanner) {
          const state = this.scanner.getState?.();
          if (state === 2 || state === 1) {
            await this.scanner.stop().catch(() => {});
          }
          await this.scanner.clear().catch(() => {});
          this.scanner = null;
        }

        const region = document.getElementById(this.scannerId);
        if (region) region.innerHTML = "";
      } finally {
        this.isStopping = false;
      }
    },

    onScanSuccess(decodedText) {
      const value = String(decodedText || "").trim();
      if (!value) return;

      const now = Date.now();

      // Doppeltrigger verhindern
      if (value === this.lastScanValue && (now - this.lastScanAt) < 1500) {
        return;
      }

      this.lastScanValue = value;
      this.lastScanAt = now;

      const preview = document.getElementById("mobileCameraScannerPreview");
      if (preview) preview.value = value;

      this.setStatus(`Code erkannt: ${value}`, "success");
      this.applyValueToTarget(value);

      if (typeof window.soundSuccess === "function") {
        window.soundSuccess();
      } else if (typeof window.beepSuccess === "function") {
        window.beepSuccess();
      }

      this.close().catch(() => {});
    },

    applyManualValue() {
      const input = document.getElementById("mobileCameraScannerManualInput");
      const value = String(input?.value || "").trim();

      if (!value) {
        this.setStatus("Bitte einen Wert eingeben.", "error");
        return;
      }

      this.applyValueToTarget(value);

      if (typeof window.soundSuccess === "function") {
        window.soundSuccess();
      } else if (typeof window.beepSuccess === "function") {
        window.beepSuccess();
      }

      this.close().catch(() => {});
    },

    applyValueToTarget(value) {
      const target = document.getElementById(this.activeTargetInputId);
      if (!target) {
        this.setStatus("Zielfeld wurde nicht gefunden.", "error");
        return;
      }

      target.value = value;
      target.dispatchEvent(new Event("input", { bubbles: true }));
      target.dispatchEvent(new Event("change", { bubbles: true }));
      target.focus();

      if (this.activeSubmitMode === "button") {
        const btn = document.getElementById(this.activeSubmitButtonId);
        if (btn) {
          btn.click();
          return;
        }
      }

      if (this.activeSubmitMode === "callback" && typeof this.activeSubmitCallback === "function") {
        this.activeSubmitCallback(value);
        return;
      }

      // Fallback: Enter simulieren
      target.dispatchEvent(new KeyboardEvent("keydown", {
        key: "Enter",
        code: "Enter",
        bubbles: true
      }));
    },

    resetUi() {
      const preview = document.getElementById("mobileCameraScannerPreview");
      const manual = document.getElementById("mobileCameraScannerManualInput");

      if (preview) preview.value = "";
      if (manual) manual.value = "";

      this.setStatus("Bereit.", "info");
    },

    setStatus(message, type = "info") {
      const el = document.getElementById("mobileCameraScannerStatus");
      if (!el) return;

      let cls = "small rounded px-2 py-1 border ";
      if (type === "success") {
        cls += "bg-success-subtle text-success border-success-subtle";
      } else if (type === "error") {
        cls += "bg-danger-subtle text-danger border-danger-subtle";
      } else {
        cls += "bg-light text-secondary border-light";
      }

      el.className = cls;
      el.textContent = message;
    },

    injectModal() {
      if (document.getElementById(this.modalId)) return;

      const html = `
        <div id="${this.modalId}" class="d-none position-fixed top-0 start-0 w-100 h-100 align-items-center justify-content-center" style="z-index: 99999; background: rgba(0,0,0,.65);">
          <div class="bg-white rounded-4 shadow p-3 mobile-camera-modal">
            <div class="d-flex align-items-center justify-content-between mb-2">
              <div class="fw-semibold" id="mobileCameraScannerTitle">Barcode mit Kamera scannen</div>
              <button type="button" class="btn btn-sm btn-outline-secondary" id="mobileCameraScannerClose">×</button>
            </div>

            <div id="mobileCameraScannerStatus" class="small rounded px-2 py-1 border bg-light text-secondary border-light mb-2">
              Bereit.
            </div>

            <div id="${this.scannerId}" class="mobile-camera-region mb-2"></div>

            <div class="mb-2">
              <label class="form-label small fw-semibold mb-1">Erkannt</label>
              <input id="mobileCameraScannerPreview" class="form-control form-control-sm" readonly>
            </div>

            <div class="border-top pt-2 mt-2">
              <label class="form-label small fw-semibold mb-1">Falls Kamera nichts erkennt: manuell eingeben</label>
              <div class="input-group input-group-sm">
                <input id="mobileCameraScannerManualInput" class="form-control" placeholder="Barcode eingeben …" autocomplete="off">
                <button type="button" id="mobileCameraScannerUseValue" class="btn btn-outline-primary">Übernehmen</button>
              </div>
            </div>

            <div class="d-flex justify-content-end gap-2 mt-3">
              <button type="button" class="btn btn-sm btn-outline-secondary" id="mobileCameraScannerCancel">Schließen</button>
            </div>
          </div>
        </div>
      `;

      document.body.insertAdjacentHTML("beforeend", html);
    },

    injectStyles() {
      if (document.getElementById("mobileCameraScanStyles")) return;

      const style = document.createElement("style");
      style.id = "mobileCameraScanStyles";
      style.textContent = `
        .mobile-camera-modal {
          width: min(96vw, 560px);
        }

        .mobile-camera-region {
          width: 100%;
          min-height: 280px;
          border: 1px solid #cbd5e1;
          border-radius: 16px;
          overflow: hidden;
          background: #0f172a;
        }

        .mobile-camera-region video {
          width: 100% !important;
          height: auto !important;
          border-radius: 16px;
        }

        @media (max-width: 768px) {
          .mobile-camera-modal {
            width: 96vw;
            max-height: 92vh;
            overflow: auto;
            border-radius: 20px;
          }

          .mobile-camera-region {
            min-height: 240px;
          }
        }
      `;

      document.head.appendChild(style);
    }
  };

  window.MobileCameraScan = MobileCameraScan;

  document.addEventListener("DOMContentLoaded", function () {
    MobileCameraScan.init();
  });
})();